// Provide an approved article for manual testing.
return [{
  json: {
    id: 'manual:https://example.com/ai-agent',
    source: 'manual',
    title: 'AI Agent 與工作流',
    url: 'https://example.com/ai-agent',
    language: 'zh-TW',
    article: {
      title: 'AI Agent 不只是生成文字',
      subtitle: '從工具呼叫到流程決策',
      summary: '本文拆解 AI Agent 在工作流中的真正角色。',
      tags: ['AI', 'n8n'],
      markdown: '# AI Agent 不只是生成文字\n\n這是一篇已通過審核的 Markdown 草稿。'
    },
    review: {
      score: 90,
      approved: true,
      issues: [],
      revisionNotes: []
    },
    metadata: {
      status: 'approved'
    }
  }
}];

// Build a deterministic GitHub path and base64 file content.
const input = $input.first().json;
const body = input.body ?? input;

if (!body.review?.approved || body.metadata?.status !== 'approved') {
  throw new Error('Only approved articles can be published');
}

if (!body.article?.title || !body.article?.markdown) {
  throw new Error('article.title and article.markdown are required');
}

const slugify = (value) => String(value)
  .normalize('NFKD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^\p{L}\p{N}]+/gu, '-')
  .replace(/^-+|-+$/g, '')
  .toLowerCase()
  .slice(0, 80) || 'untitled';

const date = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Asia/Taipei',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit'
}).format(new Date());

const slug = slugify(body.article.title);
const path = `${body.draftDirectory}/${date}-${slug}.md`;

const frontMatter = [
  '---',
  `title: "${String(body.article.title).replace(/"/g, '\\"')}"`,
  `subtitle: "${String(body.article.subtitle ?? '').replace(/"/g, '\\"')}"`,
  `summary: "${String(body.article.summary ?? '').replace(/"/g, '\\"')}"`,
  `tags: [${(body.article.tags ?? []).map((tag) => `"${String(tag).replace(/"/g, '\\"')}"`).join(', ')}]`,
  `source_url: "${String(body.url ?? '').replace(/"/g, '\\"')}"`,
  `review_score: ${Number(body.review.score ?? 0)}`,
  `created_at: "${new Date().toISOString()}"`,
  'status: draft',
  '---',
  ''
].join('\n');

const fileContent = `${frontMatter}${body.article.markdown.trim()}\n`;

return [{
  json: {
    original: body,
    githubOwner: body.githubOwner,
    githubRepo: body.githubRepo,
    githubBranch: body.githubBranch,
    path,
    commitMessage: `docs: add draft ${body.article.title}`,
    contentBase64: Buffer.from(fileContent, 'utf8').toString('base64')
  }
}];

// Extract the current file SHA when the draft already exists.
const response = $input.first().json;
const request = $('BuildGitHubDraft').first().json;
const statusCode = response.statusCode ?? 0;

if (![200, 404].includes(statusCode)) {
  throw new Error(`GitHub file lookup failed with status ${statusCode}`);
}

return [{
  json: {
    ...request,
    existingSha: statusCode === 200 ? String(response.body?.sha ?? '') : '',
    fileExists: statusCode === 200
  }
}];

// Return a compact publication result.
const response = $input.first().json;
const request = $('ParseExistingDraft').first().json;
const original = request.original;

return [{
  json: {
    ...original,
    publication: {
      provider: 'github',
      repository: `${request.githubOwner}/${request.githubRepo}`,
      branch: request.githubBranch,
      path: request.path,
      fileUrl: String(response.content?.html_url ?? ''),
      commitUrl: String(response.commit?.html_url ?? ''),
      action: request.fileExists ? 'updated' : 'created'
    },
    metadata: {
      ...original.metadata,
      publisher: '08-publisher',
      publisherVersion: '0.8.0',
      status: 'published_to_drafts',
      publishedAt: new Date().toISOString()
    }
  }
}];
